async () => {
    try {
      console.log('[E2E] Etapa 1: aguardando questionario');
      await waitFor(element(by.id('input-peso-atual'))).toBeVisible().withTimeout(5000);
      await captureStep('step-1-app-open');
      console.log('[E2E] Etapa 2 e 3: preenchendo e enviando questionario');
      await fillQuestionnaireAndContinue();
      await captureStep('step-2-questionario-preenchido');
      console.log('[E2E] Etapa 4: validando chegada na home');
      await waitFor(element(by.id('home-ready'))).toBeVisible().withTimeout(5000);
      await waitFor(element(by.id('tab-treino'))).toBeVisible().withTimeout(5000);
      console.log('[E2E] Etapa 5: navegando para treino');
      await waitFor(element(by.id('tab-treino'))).toBeVisible().withTimeout(5000);
      await element(by.id('tab-treino')).tap();
      const hasWorkoutHubCta = await isVisibleById('btn-iniciar-treino', 5000);
      if (hasWorkoutHubCta) {
        await waitFor(element(by.id('btn-iniciar-treino'))).toBeVisible().withTimeout(5000);
        await element(by.id('btn-iniciar-treino')).tap();
      }
      await captureStep('step-3-entrada-treino');
      console.log('[E2E] Etapa 6: preenchendo serie');
      await waitFor(element(by.id('input-peso'))).toBeVisible().withTimeout(5000);
      await waitFor(element(by.id('input-reps'))).toBeVisible().withTimeout(5000);
      await element(by.id('input-peso')).tap();
      await element(by.id('input-peso')).replaceText('80');
      await expect(element(by.id('input-peso'))).toHaveText('80');
      await element(by.id('input-reps')).tap();
      await element(by.id('input-reps')).replaceText('10');
      await expect(element(by.id('input-reps'))).toHaveText('10');
      await device.pressBack();
      console.log('[E2E] Etapa 7: salvando serie');
      await waitFor(element(by.id('btn-salvar-serie'))).toBeVisible().withTimeout(5000);
      await element(by.id('btn-salvar-serie')).tap();
      console.log('[E2E] Etapa 8: validando serie salva');
      await waitFor(element(by.id('serie-salva-indicator'))).toBeVisible().withTimeout(5000);
      await captureStep('step-4-serie-salva');
    } catch (error) {
      console.log('[E2E] Falha no fluxo:', error?.message || error);
      await captureStep('step-error');
      throw error;
    }
  }

